mapper.sql:
WITH BASE_SEMINAR AS ( SELECT * FROM TB_LMS_SMNR WHERE DELYN = 'N'
AND SMNR_ID = #{seminarId}
AND SBJCT_ID = #{crsCreCd}
AND ( LOWER(SEMINAR_NM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.SBJCT_ID IN ( SELECT AA.SBJCT_ID FROM TB_LMS_SBJCT AA JOIN TB_LMS_TERM_CRE_CRS_RLTN BB ON AA.SBJCT_ID = BB.SBJCT_ID WHERE AA.DELYN = 'N' AND BB.CRS_SMSTR_ID = #{termCd} )
AND A.SBJCT_ID IN ( SELECT AA.SBJCT_ID FROM TB_LMS_SBJCT AA JOIN TB_LMS_TERM_CRE_CRS_RLTN BB ON AA.SBJCT_ID = BB.SBJCT_ID WHERE AA.DELYN = 'N'
AND AA.SBJCT_ID = #{creYear}
AND AA.CRS_ID = #{creTerm}
)
), SEMINAR_ABSENT_CNT AS ( SELECT A.SMNR_ID, COUNT(AA.STD_ID) AS seminarAbsentUserCnt FROM TB_LMS_SMNR A JOIN TB_LMS_ATNDLC_SBJCT AA ON A.SBJCT_ID = AA.SBJCT_ID LEFT JOIN TB_LMS_SMNR_ATND BB ON AA.STD_ID = BB.STD_ID AND BB.SMNR_ID = A.SMNR_ID WHERE A.DELYN = 'N' AND AA.ATNDLC_STSCD = 'S' AND AA.AUDITYN = 'N' AND (BB.ATND_STSCD = 'ABSENT' OR BB.ATND_STSCD IS NULL) GROUP BY A.SMNR_ID ) SELECT ROW_NUMBER() OVER (ORDER BY A.SMNR_SDTTM, A.FRST_INQ_DTTM) AS lineNo, A.*,
-- 세미나 상태 CASE WHEN (TO_DATE(A.SMNR_SDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 > 0 THEN '대기' WHEN (TO_DATE(A.SMNR_SDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 < 0 AND (TO_DATE(A.SMNR_EDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 > 0 THEN '진행' WHEN (TO_DATE(A.SMNR_EDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 < 0 THEN '완료' END AS seminarStatus,
-- 시작 여부 CASE WHEN (TO_DATE(A.SMNR_SDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 <= 600 THEN 'Y' ELSE 'N' END AS seminarStartYn,
-- 종료 여부 CASE WHEN TRUNC(TO_DATE(A.SMNR_EDTTM, 'YYYYMMDDHH24MISS') + 1) - TRUNC(SYSDATE) <= 0 THEN 'Y' ELSE 'N' END AS seminarEndYn,
-- 결석자 수 (WITH 절에서 가져옴) NVL(SAC.seminarAbsentUserCnt, 0) AS seminarAbsentUserCnt
FROM BASE_SEMINAR A LEFT JOIN SEMINAR_ABSENT_CNT SAC ON A.SMNR_ID = SAC.SMNR_ID ORDER BY A.SMNR_SDTTM DESC, A.FRST_INQ_DTTM DESC

mapper.insert:
		/*
             SQL ID : SeminarDAO.insert
            	 설  명 : 세미나 등록
         */
         INSERT INTO TB_LMS_SMNR (
         	  SMNR_ID
			, SBJCT_ID
			, LCTR_SCHDL_ID
			, SBJCT_LCTR_CLASTM_ID
			, SEMINAR_NM
			, SMNR_CTS
			, SMNR_CTGRCD
			, SMNR_SDTTM
			, SMNR_EDTTM
			, SMNR_MNTS
			, PROF_ONLY_URL
			, PTCP_URL
			, ZOOM_ID
			, ZOOM_PSWD
			, ATNDC_PROCYN
			, AUTO_RCDYN
			, DELYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
         ) VALUES (
         	  #{seminarId}
         	, #{crsCreCd}
         	, #{lessonScheduleId}
         	, #{lessonTimeId}
         	, #{seminarNm}
         	, #{seminarCts}
         	, #{seminarCtgrCd}
         	, #{seminarStartDttm}
         	, #{seminarEndDttm}
         	, #{seminarTime}
         	, #{hostUrl}
         	, #{joinUrl}
         	, #{zoomId}
         	, #{zoomPw}
         	, NVL(#{attProcYn}, 'N')
         	, #{autoRecordYn}
         	, NVL(#{delYn}, 'N')
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
         )

mapper.update:
		/*
             SQL ID : SeminarDAO.update
            	 설  명 : 세미나 수정
         */
         UPDATE TB_LMS_SMNR SET
         	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, LCTR_SCHDL_ID = #{lessonScheduleId}
         	, SBJCT_LCTR_CLASTM_ID = #{lessonTimeId}
         	, PROF_ONLY_URL = #{hostUrl}
         	, PTCP_URL = #{joinUrl}
         	, ZOOM_ID = #{zoomId}
         	, ZOOM_PSWD = #{zoomPw}

         	, SEMINAR_NM = #{seminarNm}


         	, SMNR_CTS = #{seminarCts}


         	, SMNR_CTGRCD = #{seminarCtgrCd}


         	, SMNR_SDTTM = #{seminarStartDttm}


         	, SMNR_EDTTM = #{seminarEndDttm}


         	, SMNR_MNTS = #{seminarTime}


         	, ATNDC_PROCYN = #{attProcYn}


         	, AUTO_RCDYN = #{autoRecordYn}

          WHERE SMNR_ID = #{seminarId}

		/*
             SQL ID : SeminarDAO.updateSeminarAttProc
            	 설  명 : 세미나 출결여부 수정
         */
         UPDATE TB_LMS_SMNR SET
         	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, ATNDC_PROCYN = 'Y'
          WHERE SMNR_ID = #{seminarId}

mapper.select:
		/*
             SQL ID : SeminarDAO.countBySchedule
            	 설  명 : 특정 주차 세미나 개설 여부
         */
         SELECT 
			COUNT(*)
		  FROM TB_LMS_SMNR
		 WHERE SBJCT_ID = #{crsCreCd}
		   AND DELYN = 'N'
		   AND LCTR_SCHDL_ID = #{lessonScheduleId}

		   AND SMNR_ID != #{seminarId}

		   AND SMNR_CTGRCD != 'free'
